/**
 * n8n Function Node: Partial Save Handler
 *
 * Receives partial payload from /fulcrum-assess-partial webhook.
 * Generates UUID resume_id, stores in workflowStaticData,
 * and prepares Zoho upsert + Resend resume email payloads.
 *
 * Features:
 *   - UUID v4 generation with collision check
 *   - Dedup by email (updates existing record, preserves resume_id)
 *   - Stores form_state as stringified JSON for Zoho Partial_Data_Blob
 *   - Accepts first_name/last_name separately (form sends these)
 *   - Falls back to splitting `name` if needed
 *
 * Input:  Partial payload with email, first_name, last_name, company_name, form_state, partial_progress_step
 * Output: Payload with resume_id, Zoho API body, and email trigger data
 */

// Generate UUID v4 with collision guard
function uuidv4(existingKeys) {
  let id;
  let attempts = 0;
  do {
    id = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, (c) => {
      const r = Math.random() * 16 | 0;
      const v = c === 'x' ? r : (r & 0x3 | 0x8);
      return v.toString(16);
    });
    attempts++;
  } while (existingKeys.has(id) && attempts < 10);
  return id;
}

const input = $input.first().json;
const email = input.email || '';
const unsubscribeToken = input.unsubscribe_token || '';
const companyName = input.company_name || '';
const companyUrl = input.company_url || '';
const partialStep = input.partial_progress_step || 1;
const formState = input.form_state || {};
const referrerUrl = input.referrer_url || '';
const browserMetadata = input.browser_metadata || {};
const clientIp = input.client_ip || '';

// Name handling — form now sends first_name/last_name separately
let firstName = input.first_name || '';
let lastName = input.last_name || '';

// Fallback: split `name` if first/last not provided
if (!firstName && input.name) {
  const parts = input.name.split(' ');
  firstName = parts[0] || '';
  lastName = parts.slice(1).join(' ') || '';
}
if (!lastName) lastName = firstName;

// Validate email
if (!email || !email.includes('@')) {
  return [{
    json: {
      error: 'Valid email is required for Save for Later',
      statusCode: 400,
    }
  }];
}

// --- Static data store ---
const staticData = $getWorkflowStaticData('global');
if (!staticData.partial_records) {
  staticData.partial_records = {};
}

const existingKeys = new Set(Object.keys(staticData.partial_records));

// --- Dedup: check for existing record by email ---
let resumeId;
let isNewRecord = true;
const existingEntry = Object.entries(staticData.partial_records).find(
  ([, record]) => record.email === email && record.partial_status === 'in_progress'
);

if (existingEntry) {
  // Update existing record — preserve UUID
  isNewRecord = false;
  resumeId = existingEntry[0];
  staticData.partial_records[resumeId] = {
    ...staticData.partial_records[resumeId],
    first_name: firstName,
    last_name: lastName,
    company_name: companyName,
    company_url: companyUrl,
    form_state: formState,
    partial_progress_step: partialStep,
    updated_at: new Date().toISOString(),
    save_count: (staticData.partial_records[resumeId].save_count || 1) + 1,
    unsubscribe_token: unsubscribeToken || staticData.partial_records[resumeId].unsubscribe_token,
  };
} else {
  // Create new record
  resumeId = uuidv4(existingKeys);
  staticData.partial_records[resumeId] = {
    email,
    first_name: firstName,
    last_name: lastName,
    company_name: companyName,
    company_url: companyUrl,
    form_state: formState,
    partial_progress_step: partialStep,
    partial_status: 'in_progress',
    created_at: new Date().toISOString(),
    updated_at: new Date().toISOString(),
    drip_emails_sent: 0,
    save_count: 1,
    unsubscribe_token: unsubscribeToken,
    referrer_url: referrerUrl,
    client_ip: clientIp,
    browser_metadata: browserMetadata,
  };
}

function env(key, fallback) {
  try { return $env[key] || fallback; } catch { return fallback; }
}

const APP_URL = env('APP_URL', 'https://leverage.fulcrumcollective.io');
const resumeUrl = `${APP_URL}?resume_id=${resumeId}`;

// --- Zoho CRM API body (for HTTP Request node) ---
const zohoApiBody = {
  data: [{
    Last_Name: lastName,
    First_Name: firstName,
    Email: email,
    Company: companyName,
    Website: companyUrl,
    Lead_Source: 'Fulcrum_Tool',
    Tag: [
      { name: 'Fulcrum' },
      { name: 'Fulcrum_Partial_Submissio' },
    ],
    partial_status: 'in_progress',
    resume_id: resumeId,
    Partial_Data_Blob: JSON.stringify(formState),
  }],
  duplicate_check_fields: ['Email'],
};

return [{
  json: {
    // Core fields
    resume_id: resumeId,
    resume_url: resumeUrl,
    email,
    first_name: firstName,
    last_name: lastName,
    company_name: companyName,
    company_url: companyUrl,
    partial_progress_step: partialStep,
    form_state: formState,
    form_state_stringified: JSON.stringify(formState),
    partial_status: 'in_progress',
    is_new_record: isNewRecord,
    unsubscribe_token: unsubscribeToken,

    // Zoho API payload
    zoho_api_body: zohoApiBody,

    // Drip control — only send immediate email for new records
    trigger_drip: {
      send_immediate: isNewRecord,
      email_1_subject: `Your Fulcrum Assessment is saved, ${firstName || 'there'}`,
    },
  }
}];

/**
 * n8n Function Node: Zoho OAuth2 Token Refresh
 *
 * Manages Zoho access token lifecycle:
 *   - Checks if current token is still valid (cached in static data)
 *   - If expired or missing, refreshes using ZOHO_REFRESH_TOKEN
 *   - Returns valid access_token for downstream Zoho API calls
 *
 * Usage: Place before any Zoho HTTP Request node.
 *        Downstream nodes reference: {{ $json.zoho_access_token }}
 *
 * Input:  Any (pass-through)
 * Output: Same data + zoho_access_token
 */

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

// Check cached token
const tokenExpiry = staticData.zoho_token_expiry || 0;
const cachedToken = staticData.zoho_access_token || '';

if (cachedToken && now < tokenExpiry) {
  // Token still valid — pass through
  return [{
    json: {
      ...$input.first().json,
      zoho_access_token: cachedToken,
    }
  }];
}

// --- Refresh token ---
function env(key, fallback) {
  try { return $env[key] || fallback; } catch { return fallback; }
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://accounts.zoho.com/oauth/v2/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: env('ZOHO_CLIENT_ID', ''),
      client_secret: env('ZOHO_CLIENT_SECRET', ''),
      refresh_token: env('ZOHO_REFRESH_TOKEN', ''),
    }).toString(),
    timeout: 10000,
  });

  if (!response.access_token) {
    throw new Error(`Zoho token refresh failed: ${JSON.stringify(response)}`);
  }

  // Cache token — Zoho tokens last 1 hour, refresh 5 min early
  staticData.zoho_access_token = response.access_token;
  staticData.zoho_token_expiry = now + ((response.expires_in || 3600) - 300) * 1000;

  return [{
    json: {
      ...$input.first().json,
      zoho_access_token: response.access_token,
    }
  }];

} catch (err) {
  console.log('Zoho token refresh failed:', err.message);

  // Return error flag — downstream nodes should check this
  return [{
    json: {
      ...$input.first().json,
      zoho_access_token: null,
      zoho_auth_error: err.message,
    }
  }];
}

/**
 * n8n Function Node: Drip Email 1 — Immediate (sent right after partial save)
 *
 * Input:  Output from 05-partial-save with resume_url, first_name, company_name, step
 * Output: Resend email payload
 */

const data = $input.first().json;
const firstName = data.first_name || (data.name || '').split(' ')[0] || 'there';
const companyName = data.company_name || 'your company';
const resumeUrl = data.resume_url || '';
const step = data.partial_progress_step || 1;
const email = data.email || '';

function env(key, fallback) {
  try { return $env[key] || fallback; } catch { return fallback; }
}

const FROM_EMAIL = env('RESEND_FROM_EMAIL', 'joe@fulcrumcollective.io');
const APP_URL = env('APP_URL', 'https://leverage.fulcrumcollective.io');
const HMAC_SECRET = env('HMAC_SECRET', 'fulcrum-dev-secret');

// --- Unsubscribe link (token pre-computed by Vercel) ---
const unsubToken = data.unsubscribe_token || '';
const unsubUrl = `${APP_URL}/api/drip/stop?email=${encodeURIComponent(email)}&token=${unsubToken}`;

const html = `<!DOCTYPE html>
<html>
<head><meta charset="utf-8"></head>
<body style="font-family: Arial, Helvetica, sans-serif; background: #F7F5F2; color: #000; padding: 40px 20px;">
  <div style="max-width: 560px; margin: 0 auto;">
    <div style="margin-bottom: 24px;">
      <a href="https://www.fulcrumcollective.io"><img src="https://fulcrumcollective.io/wp-content/uploads/2026/03/Fulcrum-Logo.png" alt="Fulcrum Collective" width="120" style="width: 120px; height: auto;" /></a>
    </div>
    <h2 style="font-size: 22px; margin-bottom: 16px;">Your progress is saved, ${firstName}</h2>
    <p style="font-size: 16px; line-height: 1.6; color: #333;">
      You made it to <strong>Step ${step} of 5</strong> on the Leverage Brief assessment for
      <strong>${companyName}</strong>. Your answers are saved — pick up right where you left off.
    </p>
    <p style="font-size: 16px; line-height: 1.6; color: #333;">
      Complete the remaining steps to receive your personalized Leverage Brief with
      strategic priorities tailored to your business.
    </p>
    <div style="text-align: center; margin: 32px 0;">
      <a href="${resumeUrl}" style="display: inline-block; background: #27E7FE; color: #000; font-weight: 600; padding: 14px 32px; border-radius: 8px; text-decoration: none; font-size: 16px;">
        Continue My Assessment &rarr;
      </a>
    </div>
    <p style="font-size: 14px; color: #666;">
      <strong>Need help?</strong> Reply to this email and our team will assist you.
    </p>
    <div style="margin-top: 32px; padding-top: 16px; border-top: 1px solid #e0ddd8;">
      <p style="font-size: 11px; color: #aaa;">
        Fulcrum Collective &middot;
        <a href="${unsubUrl}" style="color: #aaa;">Unsubscribe</a>
      </p>
    </div>
  </div>
</body>
</html>`;

return [{
  json: {
    resend_payload: {
      from: FROM_EMAIL,
      to: email,
      reply_to: 'joe@fulcrumcollective.io',
      subject: `Your Fulcrum Assessment is saved, ${firstName}`,
      html,
    },
    // Pass through original data
    ...data,
  }
}];

