/**
 * n8n Function Node: Get Partial Data (Resume Retrieval)
 *
 * Receives GET request with resume_id query param.
 * Looks up stored partial record and returns form_state + step.
 *
 * Input:  Query param resume_id
 * Output: { form_state, partial_progress_step } or 404
 */

const resumeId = $input.first().json.query?.resume_id
  || $input.first().json.resume_id
  || '';

if (!resumeId) {
  return [{
    json: {
      error: 'resume_id is required',
      statusCode: 400,
    }
  }];
}

const staticData = $getWorkflowStaticData('global');
const partialRecords = staticData.partial_records || {};
const record = partialRecords[resumeId];

if (!record) {
  return [{
    json: {
      error: 'Resume session not found or expired',
      statusCode: 404,
    }
  }];
}

// Don't return completed records for resume
if (record.partial_status === 'completed') {
  return [{
    json: {
      error: 'This assessment has already been completed',
      statusCode: 410,
    }
  }];
}

return [{
  json: {
    resume_id: resumeId,
    form_state: record.form_state,
    partial_progress_step: record.partial_progress_step,
    email: record.email,
    name: record.name,
    company_name: record.company_name,
  }
}];

/**
 * n8n Function Node: Drip Stop Handler
 *
 * Receives webhook from Next.js /api/drip/stop endpoint
 * when a lead clicks the unsubscribe link in a drip email.
 *
 * Adds the email to the stopped_emails list in static data.
 * Both the drip check (07) and nurture check (12) reference this list.
 *
 * Input:  { email: string, action: 'stop_drip', stopped_at: string }
 * Output: { ok: true, email, stopped: true }
 */

const data = $input.first().json;
const email = (data.email || '').toLowerCase();

if (!email) {
  return [{ json: { error: 'No email provided', statusCode: 400 } }];
}

const staticData = $getWorkflowStaticData('global');

// Add to stopped emails list
if (!staticData.stopped_emails) staticData.stopped_emails = {};
staticData.stopped_emails[email] = data.stopped_at || new Date().toISOString();

// Also mark any active partial record as unsubscribed
if (staticData.partial_records) {
  for (const [resumeId, record] of Object.entries(staticData.partial_records)) {
    if (record.email === email && record.partial_status === 'in_progress') {
      staticData.partial_records[resumeId].partial_status = 'unsubscribed';
      staticData.partial_records[resumeId].unsubscribed_at = new Date().toISOString();
    }
  }
}

// Also mark any active nurture lead as unsubscribed
if (staticData.nurture_leads && staticData.nurture_leads[email]) {
  staticData.nurture_leads[email].nurture_status = 'unsubscribed';
}

return [{ json: { ok: true, email, stopped: true } }];

/**
 * n8n Function Node: Zoho OAuth2 Token Refresh
 *
 * Manages Zoho access token lifecycle:
 *   - Checks if current token is still valid (cached in static data)
 *   - If expired or missing, refreshes using ZOHO_REFRESH_TOKEN
 *   - Returns valid access_token for downstream Zoho API calls
 *
 * Usage: Place before any Zoho HTTP Request node.
 *        Downstream nodes reference: {{ $json.zoho_access_token }}
 *
 * Input:  Any (pass-through)
 * Output: Same data + zoho_access_token
 */

const staticData = $getWorkflowStaticData('global');
const now = Date.now();

// Check cached token
const tokenExpiry = staticData.zoho_token_expiry || 0;
const cachedToken = staticData.zoho_access_token || '';

if (cachedToken && now < tokenExpiry) {
  // Token still valid — pass through
  return [{
    json: {
      ...$input.first().json,
      zoho_access_token: cachedToken,
    }
  }];
}

// --- Refresh token ---
function env(key, fallback) {
  try { return $env[key] || fallback; } catch { return fallback; }
}

try {
  const response = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://accounts.zoho.com/oauth/v2/token',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: env('ZOHO_CLIENT_ID', ''),
      client_secret: env('ZOHO_CLIENT_SECRET', ''),
      refresh_token: env('ZOHO_REFRESH_TOKEN', ''),
    }).toString(),
    timeout: 10000,
  });

  if (!response.access_token) {
    throw new Error(`Zoho token refresh failed: ${JSON.stringify(response)}`);
  }

  // Cache token — Zoho tokens last 1 hour, refresh 5 min early
  staticData.zoho_access_token = response.access_token;
  staticData.zoho_token_expiry = now + ((response.expires_in || 3600) - 300) * 1000;

  return [{
    json: {
      ...$input.first().json,
      zoho_access_token: response.access_token,
    }
  }];

} catch (err) {
  console.log('Zoho token refresh failed:', err.message);

  // Return error flag — downstream nodes should check this
  return [{
    json: {
      ...$input.first().json,
      zoho_access_token: null,
      zoho_auth_error: err.message,
    }
  }];
}

/**
 * n8n Function Node: Drip Email Check + Send via Resend
 *
 * Called by n8n Schedule Trigger (runs every hour).
 * Iterates partial_records and checks if drip emails need sending.
 *
 * STOP CONDITIONS:
 *   1. Lead completed assessment (partial_status = 'completed' in Zoho)
 *   2. Lead clicked unsubscribe link (drip_stopped = true in static data)
 *   3. Joe manually set Drip_Stopped in Zoho
 *   4. 30 days elapsed → mark abandoned
 *
 * Email sequence (resume nurture for partial submits):
 *   Email 1 — Immediate (sent by 05-partial-save, NOT this node)
 *   Email 2 — T+24h
 *   Email 3 — T+72h (final)
 *
 * All emails sent via Resend HTTP API.
 * Each email includes an unsubscribe link: /api/drip/stop?email=...&token=...
 *
 * Input:  Triggered by schedule. Receives zoho_access_token from upstream auth node.
 * Output: Array of Resend email payloads to send (downstream HTTP Request node)
 */

const staticData = $getWorkflowStaticData('global');
const partialRecords = staticData.partial_records || {};
const stoppedEmails = staticData.stopped_emails || {};
const now = Date.now();
const HOUR = 3600000;
const zohoToken = $input.first().json.zoho_access_token || null;
function env(key, fallback) {
  try { return $env[key] || fallback; } catch { return fallback; }
}

const HMAC_SECRET = env('HMAC_SECRET', 'fulcrum-dev-secret');
const APP_URL = env('APP_URL', 'https://leverage.fulcrumcollective.io');
const FROM_EMAIL = env('RESEND_FROM_EMAIL', 'joe@fulcrumcollective.io');

const emailsToSend = [];

for (const [resumeId, record] of Object.entries(partialRecords)) {
  // Skip completed or abandoned
  if (record.partial_status !== 'in_progress') continue;

  // Check stop list (unsubscribe clicks)
  if (stoppedEmails[record.email]) {
    partialRecords[resumeId].partial_status = 'unsubscribed';
    partialRecords[resumeId].unsubscribed_at = stoppedEmails[record.email];
    continue;
  }

  const createdAt = new Date(record.created_at).getTime();
  const emailsSent = record.drip_emails_sent || 0;
  const hoursSinceCreated = (now - createdAt) / HOUR;

  // Mark as abandoned after 30 days
  if (hoursSinceCreated > 720) {
    partialRecords[resumeId].partial_status = 'abandoned';
    partialRecords[resumeId].abandoned_at = new Date().toISOString();
    continue;
  }

  // Only check for Email 2 or Email 3 timing
  const shouldSendEmail2 = emailsSent === 1 && hoursSinceCreated >= 24;
  const shouldSendEmail3 = emailsSent === 2 && hoursSinceCreated >= 72;

  if (!shouldSendEmail2 && !shouldSendEmail3) continue;

  // --- HALT CONDITION: Check Zoho before sending ---
  if (zohoToken) {
    try {
      const zohoResponse = await this.helpers.httpRequest({
        method: 'GET',
        url: `https://www.zohoapis.com/crm/v2/Leads/search?email=${encodeURIComponent(record.email)}`,
        headers: { 'Authorization': `Zoho-oauthtoken ${zohoToken}` },
        timeout: 10000,
      });

      const lead = zohoResponse?.data?.[0];
      if (lead) {
        if (lead.partial_status === 'completed') {
          partialRecords[resumeId].partial_status = 'completed';
          continue;
        }
        if (lead.Drip_Stopped === true) {
          partialRecords[resumeId].partial_status = 'unsubscribed';
          continue;
        }
      }
    } catch (zohoErr) {
      // Zoho check failed — fail-open, still send email
      console.log('Zoho check failed:', zohoErr.message);
    }
  }

  // --- Build unsubscribe link (token stored in record by partial-save) ---
  const unsubToken = record.unsubscribe_token || '';
  const unsubUrl = `${APP_URL}/api/drip/stop?email=${encodeURIComponent(record.email)}&token=${unsubToken}`;

  // --- Build email payload ---
  const firstName = record.first_name || (record.name || '').split(' ')[0] || 'there';
  const companyName = record.company_name || 'your company';
  const resumeUrl = `${APP_URL}?resume_id=${resumeId}`;

  if (shouldSendEmail2) {
    emailsToSend.push({
      resume_id: resumeId,
      resend_payload: {
        from: FROM_EMAIL,
        to: record.email,
        reply_to: 'joe@fulcrumcollective.io',
        subject: `Still thinking it over, ${firstName}?`,
        html: buildEmail2Html(firstName, companyName, resumeUrl, unsubUrl),
      },
    });
    partialRecords[resumeId].drip_emails_sent = 2;
    partialRecords[resumeId].drip_2_sent_at = new Date().toISOString();
  }

  if (shouldSendEmail3) {
    emailsToSend.push({
      resume_id: resumeId,
      resend_payload: {
        from: FROM_EMAIL,
        to: record.email,
        reply_to: 'joe@fulcrumcollective.io',
        subject: `Last chance: Your Leverage Brief assessment is expiring, ${firstName}`,
        html: buildEmail3Html(firstName, companyName, resumeUrl, unsubUrl),
      },
    });
    partialRecords[resumeId].drip_emails_sent = 3;
    partialRecords[resumeId].drip_3_sent_at = new Date().toISOString();
  }
}

// Persist updates
staticData.partial_records = partialRecords;
staticData.stopped_emails = stoppedEmails;

if (emailsToSend.length === 0) {
  return [{ json: { no_emails: true, records_scanned: Object.keys(partialRecords).length } }];
}

return emailsToSend.map(e => ({ json: e }));

